mapper.select:
SELECT S.STAFF_ID, S.STAFF_NO, S.STAFF_NM, S.STAFF_RMK1, S.STAFF_CLS, C1.COM_CONTENT_1 AS STAFF_CLS_NAME, S.STAFF_SALESSTATUS, C2.COM_CONTENT_1 AS STAFF_SALESSTATUS_NAME FROM STAFF_TBL S LEFT JOIN COM_TBL C1 ON S.STAFF_CLS = C1.COM_CD AND C1.COM_ID = 'STAFF_CLS' LEFT JOIN COM_TBL C2 ON S.STAFF_SALESSTATUS = C2.COM_CD AND C2.COM_ID = 'STAFF_SALESSTATUS'
AND S.STAFF_NM LIKE CONCAT('%', #{staffNm}, '%')
AND S.STAFF_CLS = #{staffCls}
AND S.STAFF_SALESSTATUS = #{staffSalesstatus}
ORDER BY S.STAFF_NO LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM STAFF_TBL S
AND S.STAFF_NM LIKE CONCAT('%', #{staffNm}, '%')
AND S.STAFF_CLS = #{staffCls}
AND S.STAFF_SALESSTATUS = #{staffSalesstatus}
